CREATE TRIGGER [dbo].[FinishedGoods_History]ON [dbo].[FinishedGoods]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.FinishedGoodsId IS NOT NULL AND d.FinishedGoodsId IS NULL THEN 'I' 		WHEN i.FinishedGoodsId IS NOT NULL AND d.FinishedGoodsId IS NOT NULL THEN 'U' 		WHEN i.FinishedGoodsId IS NULL AND d.FinishedGoodsId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.FinishedGoodsId = d.FinishedGoodsId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_FinishedGoods([FinishedGoodsId], [ContainerId], [ContainerQuantityAtTransactionDate], [IsReturnedToProduction], [TransactionDate], [TransactionDateUtc], [ReturnToProductionDate], [ReturnToProductionDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [FinishedGoodsId], [ContainerId], [ContainerQuantityAtTransactionDate], [IsReturnedToProduction], [TransactionDate], [TransactionDateUtc], [ReturnToProductionDate], [ReturnToProductionDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_FinishedGoods([FinishedGoodsId], [ContainerId], [ContainerQuantityAtTransactionDate], [IsReturnedToProduction], [TransactionDate], [TransactionDateUtc], [ReturnToProductionDate], [ReturnToProductionDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [FinishedGoodsId], [ContainerId], [ContainerQuantityAtTransactionDate], [IsReturnedToProduction], [TransactionDate], [TransactionDateUtc], [ReturnToProductionDate], [ReturnToProductionDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND